import React, { useEffect, useState } from 'react';
import API from '../api/axios';

export default function Clients() {
  const [clients, setClients] = useState([]);
  const [leads, setLeads] = useState([]);
  const [selected, setSelected] = useState(null);
  const [interactions, setInteractions] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [showIntForm, setShowIntForm] = useState(false);
  const [form, setForm] = useState({ lead_id: '', name: '', email: '', phone: '', client_type: 'buyer', preferences: '' });
  const [intForm, setIntForm] = useState({ type: 'call', notes: '' });

  const fetchClients = () => API.get('/clients').then(r => setClients(r.data));
  const fetchLeads = () => API.get('/leads').then(r => setLeads(r.data));

  useEffect(() => { fetchClients(); fetchLeads(); }, []);

  const openClient = async (client) => {
    setSelected(client);
    const res = await API.get(`/clients/${client.id}/interactions`);
    setInteractions(res.data);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    await API.post('/clients', form);
    setShowForm(false);
    setForm({ lead_id: '', name: '', email: '', phone: '', client_type: 'buyer', preferences: '' });
    fetchClients();
  };

  const logInteraction = async (e) => {
    e.preventDefault();
    await API.post(`/clients/${selected.id}/interactions`, intForm);
    setShowIntForm(false);
    setIntForm({ type: 'call', notes: '' });
    const res = await API.get(`/clients/${selected.id}/interactions`);
    setInteractions(res.data);
  };

  const TYPE_COLORS = { buyer: '#3b82f6', seller: '#f59e0b', both: '#8b5cf6' };
  const INT_ICONS = { call: '📞', sms: '💬', email: '📧', visit: '🏠' };

  return (
    <div style={styles.page}>
      <div style={styles.header}>
        <h1 style={styles.title}>👥 Clients</h1>
        <button onClick={() => setShowForm(!showForm)} style={styles.addBtn}>+ Add Client</button>
      </div>

      {/* Add Client Form */}
      {showForm && (
        <div style={styles.formBox}>
          <h3 style={{ marginBottom: 16 }}>New Client</h3>
          <form onSubmit={handleSubmit} style={styles.formGrid}>
            <input placeholder="Name *" required style={styles.input} value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} />
            <input placeholder="Email" style={styles.input} value={form.email} onChange={e => setForm({ ...form, email: e.target.value })} />
            <input placeholder="Phone" style={styles.input} value={form.phone} onChange={e => setForm({ ...form, phone: e.target.value })} />
            <select style={styles.input} value={form.client_type} onChange={e => setForm({ ...form, client_type: e.target.value })}>
              <option value="buyer">Buyer</option>
              <option value="seller">Seller</option>
              <option value="both">Both</option>
            </select>
            <select style={styles.input} value={form.lead_id} onChange={e => setForm({ ...form, lead_id: e.target.value })}>
              <option value="">Link to Lead (optional)</option>
              {leads.map(l => <option key={l.id} value={l.id}>{l.name} — {l.status}</option>)}
            </select>
            <input placeholder="Preferences" style={styles.input} value={form.preferences} onChange={e => setForm({ ...form, preferences: e.target.value })} />
            <div style={{ gridColumn: '1/-1', display: 'flex', gap: 10 }}>
              <button type="submit" style={styles.addBtn}>Save Client</button>
              <button type="button" onClick={() => setShowForm(false)} style={styles.cancelBtn}>Cancel</button>
            </div>
          </form>
        </div>
      )}

      <div style={styles.layout}>
        {/* Client List */}
        <div style={styles.list}>
          {clients.length === 0 && <div style={styles.empty}>No clients yet.</div>}
          {clients.map(c => (
            <div key={c.id} onClick={() => openClient(c)}
              style={{ ...styles.clientCard, ...(selected?.id === c.id ? styles.activeCard : {}) }}>
              <div style={styles.avatar}>{c.name?.[0]?.toUpperCase()}</div>
              <div style={{ flex: 1 }}>
                <div style={styles.clientName}>{c.name}</div>
                <div style={styles.clientMeta}>{c.email || c.phone || '—'}</div>
              </div>
              <span style={{ ...styles.typeBadge, background: TYPE_COLORS[c.client_type] + '20', color: TYPE_COLORS[c.client_type] }}>
                {c.client_type}
              </span>
            </div>
          ))}
        </div>

        {/* Client Detail Panel */}
        {selected ? (
          <div style={styles.detail}>
            <div style={styles.detailHeader}>
              <div>
                <h2 style={{ fontSize: 18, fontWeight: 700, color: '#1e293b' }}>{selected.name}</h2>
                <div style={{ fontSize: 13, color: '#64748b', marginTop: 2 }}>{selected.email} • {selected.phone}</div>
              </div>
              <span style={{ ...styles.typeBadge, background: TYPE_COLORS[selected.client_type] + '20', color: TYPE_COLORS[selected.client_type], fontSize: 13, padding: '4px 12px' }}>
                {selected.client_type}
              </span>
            </div>

            {selected.preferences && (
              <div style={styles.prefBox}>
                <strong>Preferences:</strong> {selected.preferences}
              </div>
            )}

            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', margin: '20px 0 12px' }}>
              <h3 style={{ fontSize: 15, fontWeight: 600, color: '#1e293b' }}>Interaction History</h3>
              <button onClick={() => setShowIntForm(!showIntForm)} style={{ ...styles.addBtn, padding: '6px 14px', fontSize: 13 }}>+ Log</button>
            </div>

            {showIntForm && (
              <form onSubmit={logInteraction} style={{ display: 'flex', gap: 10, marginBottom: 16 }}>
                <select style={styles.input} value={intForm.type} onChange={e => setIntForm({ ...intForm, type: e.target.value })}>
                  <option value="call">📞 Call</option>
                  <option value="sms">💬 SMS</option>
                  <option value="email">📧 Email</option>
                  <option value="visit">🏠 Visit</option>
                </select>
                <input placeholder="Notes..." style={{ ...styles.input, flex: 1 }} value={intForm.notes}
                  onChange={e => setIntForm({ ...intForm, notes: e.target.value })} />
                <button type="submit" style={styles.addBtn}>Log</button>
              </form>
            )}

            <div style={styles.timeline}>
              {interactions.length === 0 && <div style={styles.empty}>No interactions yet.</div>}
              {interactions.map(i => (
                <div key={i.id} style={styles.timelineItem}>
                  <div style={styles.timelineIcon}>{INT_ICONS[i.type]}</div>
                  <div>
                    <div style={styles.timelineNote}>{i.notes || 'No notes'}</div>
                    <div style={styles.timelineMeta}>
                      {i.agent_name || 'Agent'} • {new Date(i.interacted_at).toLocaleString()}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        ) : (
          <div style={{ ...styles.detail, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <div style={{ textAlign: 'center', color: '#94a3b8' }}>
              <div style={{ fontSize: 48 }}>👥</div>
              <div style={{ marginTop: 10, fontSize: 14 }}>Select a client to view details</div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

const styles = {
  page: { padding: 24 },
  header: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 },
  title: { fontSize: 22, fontWeight: 700, color: '#1e293b' },
  addBtn: { padding: '10px 20px', background: '#3b82f6', color: '#fff', border: 'none', borderRadius: 8, cursor: 'pointer', fontWeight: 600, fontSize: 14 },
  cancelBtn: { padding: '10px 20px', background: '#e2e8f0', color: '#475569', border: 'none', borderRadius: 8, cursor: 'pointer' },
  formBox: { background: '#fff', padding: 20, borderRadius: 10, marginBottom: 20, boxShadow: '0 1px 8px rgba(0,0,0,0.08)' },
  formGrid: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 },
  input: { padding: '10px 12px', border: '1px solid #e2e8f0', borderRadius: 8, fontSize: 14, outline: 'none' },
  layout: { display: 'grid', gridTemplateColumns: '320px 1fr', gap: 16 },
  list: { display: 'flex', flexDirection: 'column', gap: 8 },
  clientCard: { background: '#fff', borderRadius: 10, padding: 14, display: 'flex', alignItems: 'center', gap: 12, cursor: 'pointer', boxShadow: '0 1px 6px rgba(0,0,0,0.06)', border: '2px solid transparent' },
  activeCard: { border: '2px solid #3b82f6' },
  avatar: { width: 40, height: 40, borderRadius: '50%', background: '#dbeafe', color: '#1d4ed8', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 700, fontSize: 16 },
  clientName: { fontWeight: 600, fontSize: 14, color: '#1e293b' },
  clientMeta: { fontSize: 12, color: '#64748b', marginTop: 2 },
  typeBadge: { padding: '2px 8px', borderRadius: 12, fontSize: 11, fontWeight: 600 },
  detail: { background: '#fff', borderRadius: 10, padding: 24, boxShadow: '0 1px 8px rgba(0,0,0,0.08)', minHeight: 300 },
  detailHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 16 },
  prefBox: { background: '#f8fafc', padding: 12, borderRadius: 8, fontSize: 13, color: '#374151', marginBottom: 8 },
  timeline: { display: 'flex', flexDirection: 'column', gap: 10 },
  timelineItem: { display: 'flex', gap: 12, alignItems: 'flex-start', padding: '10px 14px', background: '#f8fafc', borderRadius: 8 },
  timelineIcon: { fontSize: 20, marginTop: 2 },
  timelineNote: { fontSize: 14, color: '#374151', fontWeight: 500 },
  timelineMeta: { fontSize: 12, color: '#94a3b8', marginTop: 3 },
  empty: { textAlign: 'center', color: '#94a3b8', padding: '30px 0', fontSize: 14 },
};
